import{c as t,Z as l,Q as i,j as r,o,m as n}from"./chunks/framework.qjzPVSkb.js";const f=JSON.parse('{"title":"多模态","description":"模型同时理解文本、图像、音频等多种输入类型的能力","frontmatter":{"title":"多模态","description":"模型同时理解文本、图像、音频等多种输入类型的能力","difficulty":"beginner"},"headers":[],"relativePath":"terms/multimodal.md","filePath":"terms/multimodal.md"}'),s={name:"terms/multimodal.md"};function d(h,e,m,c,g,u){const a=l("DifficultyBadge");return i(),r("div",null,[o(a,{level:"beginner"}),e[0]||(e[0]=n('<h1 id="多模态" tabindex="-1">多模态 <a class="header-anchor" href="#多模态" aria-label="Permalink to &quot;多模态&quot;">​</a></h1><p>我们人类看世界是用眼睛（视觉）、耳朵（听觉）、嘴巴（语言）一起工作的——AI 的多模态能力就是让模型也能这样。</p><h2 id="一句话解释" tabindex="-1">一句话解释 <a class="header-anchor" href="#一句话解释" aria-label="Permalink to &quot;一句话解释&quot;">​</a></h2><p>多模态（Multimodal）让模型能同时处理和关联文本、图像、音频、视频等多种类型的数据。GPT-4o、Gemini、通义千问等模型都已支持多模态输入输出。</p><h2 id="通俗类比" tabindex="-1">通俗类比 <a class="header-anchor" href="#通俗类比" aria-label="Permalink to &quot;通俗类比&quot;">​</a></h2><p>早期的 AI 像是<strong>不同的专家各管一摊</strong>：有人只看文字，有人只看图，彼此不沟通。</p><p>多模态 AI 则像一个<strong>全科医生</strong>——你给他看一张 X 光片（图像），口述症状（文本），他就能综合分析并给出诊断。不同信息在他脑中自然融合。</p><h2 id="技术定义" tabindex="-1">技术定义 <a class="header-anchor" href="#技术定义" aria-label="Permalink to &quot;技术定义&quot;">​</a></h2><p>多模态模型的实现有多种路线：</p><ol><li><strong>编码器融合</strong>：用不同的编码器分别处理文本（Text Encoder）和图像（Vision Encoder），然后将两者的向量表示对齐到同一个语义空间</li><li><strong>原生多模态</strong>：从训练开始就同时喂入多模态数据，让模型在参数层面建立跨模态关联</li><li><strong>工具调用</strong>：模型本身只处理文本，但可以调用外部工具（OCR、语音识别等）来处理其他模态</li></ol><p>常见多模态任务：</p><ul><li><strong>图像理解</strong>：描述图片内容、回答关于图片的问题</li><li><strong>视觉问答（VQA）</strong>：根据图片回答问题</li><li><strong>文生图</strong>：根据文字描述生成图像（如 DALL·E、Midjourney）</li><li><strong>语音交互</strong>：实时语音对话</li></ul><h2 id="关联术语" tabindex="-1">关联术语 <a class="header-anchor" href="#关联术语" aria-label="Permalink to &quot;关联术语&quot;">​</a></h2><ul><li><a href="/ai-knowledge/terms/llm.html">大语言模型 (LLM)</a> —— 多模态模型的基础</li><li><a href="/ai-knowledge/terms/training-inference.html">训练 / 推理</a> —— 多模态模型训练需要更多数据</li></ul><h2 id="延伸阅读" tabindex="-1">延伸阅读 <a class="header-anchor" href="#延伸阅读" aria-label="Permalink to &quot;延伸阅读&quot;">​</a></h2><ul><li><a href="https://openai.com/index/hello-gpt-4o/" target="_blank" rel="noreferrer">GPT-4o 官方介绍</a></li><li><a href="https://deepmind.google/technologies/gemini/" target="_blank" rel="noreferrer">Gemini 多模态能力</a></li><li><a href="/ai-knowledge/dev/multimodal-vision.html">多模态编程 (Vision API)</a> — 用代码让 AI「看见」图片</li></ul>',16))])}const _=t(s,[["render",d]]);export{f as __pageData,_ as default};
